// SLOW: creates a new String object each iteration
String result = "";
for (int i = 0; i < 1000; i++) {
    // Each += creates a new String (O(n^2) time!)
    result += "Item " + i + ", ";
}

// FAST: StringBuilder mutates one buffer (O(n) time)
StringBuilder sb = new StringBuilder();
for (int i = 0; i < 1000; i++) {
    // append() modifies the internal buffer
    sb.append("Item ").append(i).append(", ");
}
String fastResult = sb.toString();

// Expected: both produce same string
// But the first approach is ~100x slower for 1000 items
// and worsens quadratically as items increase
